const crypto = require('crypto');

function verifyWebhookSignature(payload, signature, secret) {
  const expectedSignature = 'sha256=' + 
    crypto.createHmac('sha256', secret)
      .update(JSON.stringify(payload))
      .digest('hex');
  
  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSignature)
  );
}`})]})]})]})}),s.jsx("section",{id:"ejemplos",children:s.jsxs(J,{children:[s.jsxs(we,{children:[s.jsxs(Ne,{className:"flex items-center gap-2",children:[s.jsx(VM,{className:"w-5 h-5 text-purple-500"}),"Ejemplos de Código"]}),s.jsx(He,{children:"Implementaciones en diferentes lenguajes"})]}),s.jsx(Q,{children:s.jsxs(on,{defaultValue:"javascript",children:[s.jsxs(Gr,{className:"grid w-full grid-cols-4",children:[s.jsx(Ue,{value:"javascript",children:"JavaScript"}),s.jsx(Ue,{value:"python",children:"Python"}),s.jsx(Ue,{value:"php",children:"PHP"}),s.jsx(Ue,{value:"curl",children:"cURL"})]}),s.jsxs(rt,{value:"javascript",className:"space-y-4",children:[s.jsxs("div",{children:[s.jsx("h4",{className:"text-sm font-medium mb-2",children:"Consultar un RNC"}),s.jsxs("div",{className:"relative",children:[s.jsx("pre",{className:"bg-[#1e1e1e] text-gray-100 p-4 rounded-lg overflow-x-auto text-sm font-mono",children:s.jsx("code",{children:`// Usando Fetch API
